ControlPropertyState.AutoRuleBindingString:
Set(previousScreen, WORKORDER_VIEW_ASSIGNED_TECHNICIAN_SV);
Set(checklistWorkOrderId, varSelectedWorkOrder.ID);

Switch(
    varSelectedWorkOrder.maint_act_type.Value,
    "M7", Navigate(TASK_CHECKLIST_PM, ScreenTransition.Fade),
    "R8", Navigate(TASK_CHECKLIST_CM, ScreenTransition.Fade)
)

With(
    {
        filteredData: Filter(
            tbl_mrl_workorder_assign,
            workorder.Id = varSelectedWorkOrder.ID && LookUp(
                tbl_mrl_users,
                ID = technician.Id
            ).role.Value = "Technician"
        )
    },
    If(
        CountRows(filteredData) = CountRows(
            Filter(
                filteredData,
                status.Value = "Submitted"
            )
        ),
         If(
            varSelectedWorkOrder.status_workorder_dmp.Value in ["SUB", "CLS1", "CLS2"],
            DisplayMode.Disabled,
            DisplayMode.Edit
        ),
        DisplayMode.Disabled
    )
)

Set(varViewPMOnly, false);
Set(previousScreen,TASK_VIEW);

UpdateContext({isPopupChecklist:false});

Switch(
    LookUp(
        tbl_mrl_workorder,
        ID = varSelectedTask.workorder.Id,
        maint_act_type.Value
    ),
    "M7", Navigate(TASK_CHECKLIST_PM, ScreenTransition.Fade),
    "R8", Navigate(TASK_CHECKLIST_CM, ScreenTransition.Fade)
)

Set(varViewPMOnly, true);
Set(previousScreen,TASK_VIEW);

// Change status new to processing
Patch(
    tbl_mrl_workorder_assign,
    LookUp(tbl_mrl_workorder_assign, ID = varSelectedTask.ID && start_date = Blank()),
    {
        status: {
            Id: 4,
            Value: "Processing"
        },
        start_date: Now()
    }
);

// log tbl_mrl_workorder_assign_log status Processing
Patch(
    tbl_mrl_workorder_assign_log,
    // 1. Try to find an existing record with these two values
    Coalesce(
        LookUp(
            tbl_mrl_workorder_assign_log, workorder_assign_id = varSelectedTask.ID && workorder_status = "Processing"
        ),
        // 2. If LookUp is blank, create a new record instead
        Defaults(tbl_mrl_workorder_assign_log)
    ),
    {
        workorder_assign_id: varSelectedTask.ID,
        workorder_no_ref: Round(varSelectedTask.workorder.Value, 0),
        workorder_status: "Processing",
        user_email: varUserRecord.email,
        user_role: varUserRecord.role.Value,
        user_department: varUserRecord.department.Value,
        location_long: Location.Longitude,
        location_lat: Location.Latitude
    }
);


Switch(
    LookUp(
        tbl_mrl_workorder,
        ID = varSelectedTask.workorder.Id,
        maint_act_type.Value
    ),
    "M7", Navigate(TASK_CHECKLIST_PM, ScreenTransition.Fade),
    "R8", Navigate(TASK_CHECKLIST_CM, ScreenTransition.Fade)
);

// 1. Start the loading state
UpdateContext({varIsLoading: true});

// 2. Perform the Refresh
Refresh(tbl_mrl_workorder);

// 3. End the loading state
UpdateContext({varIsLoading: false});

Notify("Data Refreshed", NotificationType.Success)
